const burger=document.getElementById("burgerBtn"),mobileMenu=document.getElementById("mobileMenu");burger.addEventListener("click",()=>{mobileMenu.classList.toggle("open")}),mobileMenu.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>mobileMenu.classList.remove("open"))});const sections=document.querySelectorAll("section[id]"),navLinks=document.querySelectorAll(".nav-links a");window.addEventListener("scroll",()=>{let e="";sections.forEach(t=>{window.scrollY>=t.offsetTop-80&&(e=t.id)}),navLinks.forEach(t=>{t.classList.toggle("active",t.getAttribute("href")==="#"+e)})});const fadeEls=document.querySelectorAll(".fade-in"),io=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&e.target.classList.add("visible")})},{threshold:.1});function handleSubmit(e){e.preventDefault();const t=e.target.querySelector(".btn-send");t.textContent="✅ Sent!",t.style.background="#22d3a5",setTimeout(()=>{t.textContent="✈ Send Message",t.style.background="",e.target.reset()},3e3)}fadeEls.forEach(e=>io.observe(e));